"use client";

import { motion, AnimatePresence } from "framer-motion";
import { Trophy, Star, Zap } from "lucide-react";
import { useEffect, useState } from "react";
import { hapticCelebration } from "@/lib/platform/haptics";

interface AchievementToastProps {
    show: boolean;
    title: string;
    description: string;
    type?: "achievement" | "level-up" | "streak";
    onClose: () => void;
}

/**
 * A ultra-premium achievement notification that screams "JUICE".
 * Features: Physics-based entry, glassmorphism, internal particle bursts (simulated),
 * and high-contrast typography.
 */
export default function AchievementToast({
    show,
    title,
    description,
    type = "achievement",
    onClose,
}: AchievementToastProps) {
    const [internalParticles, setInternalParticles] = useState<number[]>([]);

    useEffect(() => {
        if (show) {
            void hapticCelebration();
            // Auto close after 5 seconds
            const timer = setTimeout(onClose, 5000);
            return () => clearTimeout(timer);
        }
    }, [show, onClose]);

    const config = {
        achievement: { icon: Trophy, color: "from-amber-400 to-orange-500", label: "Achievement!" },
        "level-up": { icon: Star, color: "from-purple-500 to-indigo-600", label: "Level Up!" },
        streak: { icon: Zap, color: "from-orange-400 to-red-600", label: "On Fire!" },
    };

    const current = config[type];
    const Icon = current.icon;

    return (
        <AnimatePresence>
            {show && (
                <motion.div
                    initial={{ y: 100, x: "-50%", opacity: 0, scale: 0.8 }}
                    animate={{ y: -40, x: "-50%", opacity: 1, scale: 1 }}
                    exit={{ y: 20, x: "-50%", opacity: 0, scale: 0.9 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    style={{ left: "50%" }}
                    className="fixed bottom-0 z-[100] w-[90%] max-w-md pointer-events-auto"
                >
                    <div className="relative group overflow-hidden rounded-[2rem] p-[3px] shadow-2xl">
                        {/* Animated Border Gradient */}
                        <div className={`absolute inset-0 bg-gradient-to-r ${current.color} animate-pulse`} />

                        {/* Main Content */}
                        <div className="relative bg-white/90 dark:bg-stone-900/95 backdrop-blur-2xl rounded-[1.8rem] p-6 flex items-center gap-5 overflow-hidden">
                            {/* Background Glow */}
                            <div className={`absolute -right-10 -top-10 w-32 h-32 bg-gradient-to-br ${current.color} opacity-20 blur-2xl rounded-full`} />

                            {/* Icon Container */}
                            <motion.div
                                initial={{ rotate: -20, scale: 0 }}
                                animate={{ rotate: 0, scale: 1 }}
                                transition={{ delay: 0.2, type: "spring" }}
                                className={`flex-shrink-0 w-16 h-16 rounded-2xl bg-gradient-to-br ${current.color} flex items-center justify-center shadow-lg transform -rotate-3 group-hover:rotate-0 transition-transform`}
                            >
                                <Icon className="w-8 h-8 text-white" />
                            </motion.div>

                            {/* Text Content */}
                            <div className="flex-1 min-w-0">
                                <span className={`text-[10px] font-black uppercase tracking-[0.2em] bg-gradient-to-r ${current.color} bg-clip-text text-transparent`}>
                                    {current.label}
                                </span>
                                <h4 className="text-xl font-black text-stone-800 dark:text-white truncate">
                                    {title}
                                </h4>
                                <p className="text-stone-500 dark:text-stone-400 text-sm font-medium leading-tight">
                                    {description}
                                </p>
                            </div>

                            {/* Close Button */}
                            <button
                                onClick={onClose}
                                className="absolute top-4 right-4 p-1 hover:bg-stone-100 dark:hover:bg-white/10 rounded-full transition-colors"
                                aria-label="Close notification"
                            >
                                <motion.div whileHover={{ rotate: 90 }}>
                                    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
                                        <path d="M15 5L5 15M5 5l10 10" />
                                    </svg>
                                </motion.div>
                            </button>

                            {/* Particle Burst Simulation (CSS Masks) */}
                            <div className="absolute inset-0 pointer-events-none opacity-50">
                                {[...Array(6)].map((_, i) => (
                                    <motion.div
                                        key={i}
                                        initial={{ scale: 0, x: "50%", y: "50%" }}
                                        animate={{
                                            scale: [0, 1, 0],
                                            x: [`${50 + (Math.random() - 0.5) * 40}%`, `${50 + (Math.random() - 0.5) * 80}%`],
                                            y: [`${50 + (Math.random() - 0.5) * 40}%`, `${50 + (Math.random() - 0.5) * 80}%`],
                                        }}
                                        transition={{ duration: 1, repeat: Infinity, delay: i * 0.5 }}
                                        className={`absolute w-2 h-2 rounded-full bg-gradient-to-r ${current.color}`}
                                    />
                                ))}
                            </div>
                        </div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { CompanionGender } from "@/lib/greeter/companion-config";
import { COMPANIONS } from "@/lib/greeter/companion-config";

interface Props {
  gender: CompanionGender;
  videoUrl: string;
  onClose: () => void;
}

export default function CompanionIntroVideo({ gender, videoUrl, onClose }: Props) {
  const companion = COMPANIONS[gender];
  const videoRef = useRef<HTMLVideoElement>(null);
  const [muted, setMuted] = useState(true);
  const [playing, setPlaying] = useState(false);
  const [ended, setEnded] = useState(false);
  const colorScheme = companion.colorScheme;

  // Auto-play muted on mount
  useEffect(() => {
    const v = videoRef.current;
    if (!v) return;
    v.muted = true;
    v.play().then(() => setPlaying(true)).catch(() => { /* autoplay blocked */ });
  }, []);

  const toggleMute = () => {
    const v = videoRef.current;
    if (!v) return;
    v.muted = !muted;
    setMuted(!muted);
  };

  return (
    <AnimatePresence>
      <motion.div
        key="intro-video"
        initial={{ opacity: 0, y: 20, scale: 0.9 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: 16, scale: 0.92 }}
        transition={{ type: "spring", stiffness: 300, damping: 26 }}
        className={`w-72 overflow-hidden rounded-2xl border shadow-2xl ${colorScheme.border} bg-black`}
        role="dialog"
        aria-label={`${companion.name}'s introduction video`}
      >
        {/* Header */}
        <div className={`flex items-center gap-2 px-3 py-2 ${colorScheme.bg}`}>
          <div className={`text-xs font-bold ${colorScheme.text} flex-1`}>
            Meet {companion.name}! 👋
          </div>
          <button
            onClick={toggleMute}
            className={`flex h-6 w-6 items-center justify-center rounded-full text-xs hover:bg-white/40 ${colorScheme.text}`}
            aria-label={muted ? "Unmute video" : "Mute video"}
            title={muted ? "Unmute" : "Mute"}
          >
            {muted ? <MuteIcon /> : <UnmuteIcon />}
          </button>
          <button
            onClick={onClose}
            className="flex h-6 w-6 items-center justify-center rounded-full text-zinc-400 hover:bg-white/40 hover:text-zinc-600"
            aria-label="Close intro video"
          >
            <XIcon />
          </button>
        </div>

        {/* Video — 16:9 inside 288px card = 162px tall */}
        <div className="relative w-full" style={{ aspectRatio: "16/9" }}>
          <video
            ref={videoRef}
            src={videoUrl}
            className="h-full w-full object-cover"
            playsInline
            muted={muted}
            onEnded={() => setEnded(true)}
            onPlay={() => setPlaying(true)}
          />
          {/* Replay overlay when ended */}
          {ended && (
            <button
              onClick={() => {
                const v = videoRef.current;
                if (!v) return;
                v.currentTime = 0;
                v.play();
                setEnded(false);
              }}
              className="absolute inset-0 flex items-center justify-center bg-black/50 text-white"
              aria-label="Replay intro"
            >
              <ReplayIcon />
            </button>
          )}
          {/* Autoplay hint if not yet playing */}
          {!playing && (
            <button
              onClick={() => {
                videoRef.current?.play().then(() => setPlaying(true)).catch(() => {});
              }}
              className="absolute inset-0 flex items-center justify-center bg-black/70"
              aria-label="Play intro video"
            >
              <PlayIcon color={gender === "female" ? "#a78bfa" : "#22d3ee"} />
            </button>
          )}
        </div>

        {/* CTA */}
        <div className="flex items-center gap-2 px-3 py-2.5">
          <p className="flex-1 text-xs text-zinc-300 leading-snug">
            {gender === "female"
              ? "I'll be with you every step of your journey! 💜"
              : "Ready to explore and learn together? Let's go! 🚀"}
          </p>
          <button
            onClick={onClose}
            className={`shrink-0 rounded-full px-3 py-1.5 text-xs font-bold text-white transition-opacity hover:opacity-90 ${
              gender === "female" ? "bg-violet-500" : "bg-cyan-500"
            }`}
          >
            Let's go →
          </button>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}

function XIcon() {
  return (
    <svg width="10" height="10" viewBox="0 0 10 10" fill="none" aria-hidden>
      <path d="M1 1l8 8M9 1l-8 8" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" />
    </svg>
  );
}

function MuteIcon() {
  return (
    <svg width="12" height="12" viewBox="0 0 12 12" fill="none" aria-hidden>
      <path d="M2 4.5h2l3-2.5v7.5L4 7H2a.5.5 0 01-.5-.5v-2A.5.5 0 012 4.5z" stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round" />
      <path d="M8 4.5l3 3m0-3l-3 3" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" />
    </svg>
  );
}

function UnmuteIcon() {
  return (
    <svg width="12" height="12" viewBox="0 0 12 12" fill="none" aria-hidden>
      <path d="M2 4.5h2l3-2.5v7.5L4 7H2a.5.5 0 01-.5-.5v-2A.5.5 0 012 4.5z" stroke="currentColor" strokeWidth="1.2" strokeLinejoin="round" />
      <path d="M9 3.5a3.5 3.5 0 010 5M7.5 4.5a2 2 0 010 3" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round" />
    </svg>
  );
}

function PlayIcon({ color }: { color: string }) {
  return (
    <svg width="48" height="48" viewBox="0 0 48 48" fill="none" aria-hidden>
      <circle cx="24" cy="24" r="22" fill="black" fillOpacity="0.5" stroke={color} strokeWidth="2" />
      <path d="M20 16l14 8-14 8V16z" fill={color} />
    </svg>
  );
}

function ReplayIcon() {
  return (
    <svg width="40" height="40" viewBox="0 0 40 40" fill="none" aria-hidden>
      <circle cx="20" cy="20" r="18" fill="black" fillOpacity="0.6" stroke="white" strokeWidth="1.5" />
      <path d="M13 20a7 7 0 107-7" stroke="white" strokeWidth="1.8" strokeLinecap="round" />
      <path d="M20 10l-3 3 3 3" stroke="white" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

"use client";

import { motion, useScroll, useTransform, AnimatePresence } from "framer-motion";
import { useRef, useState, useEffect } from "react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import MascotFriend from "./KoydoMascotFriends";
import { hapticSelection, hapticSuccess } from "@/lib/platform/haptics";
import { Brain, Flame, Atom, Palette, Cpu, Rocket, ShieldCheck, Beaker, Zap, Box, Search, ChevronRight, Code, Leaf, TrendingUp, Globe, TreePine, Music, Mountain, Bot, Wind, History as HistoryIcon, Microscope, Navigation, Grid3X3, ShieldAlert, Scale, Compass, Building2, Construction, Lock, BookOpen, CircuitBoard } from "lucide-react";
import Link from "next/link";

interface PlanetNode {
    id: string;
    name: string;
    icon: any;
    color: string;
    accent: string;
