"use client";

import { useEffect, useRef, useState } from "react";

type Particle = {
    x: number;
    y: number;
    vx: number;
    vy: number;
    rotation: number;
    vRotation: number;
    color: string;
    size: number;
    shape: "circle" | "square";
};

type JuicyConfettiProps = {
    active?: boolean;
    onComplete?: () => void;
    durationMs?: number;
    particleCount?: number;
};

const COLORS = ["#FF5F7F", "#22B46E", "#FFB341", "#C2185B", "#8B5CF6", "#0EA5E9"];

export default function JuicyConfetti({
    active = false,
    onComplete,
    durationMs = 3000,
    particleCount = 80,
}: JuicyConfettiProps) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [shouldRender, setShouldRender] = useState(false);
    const particles = useRef<Particle[]>([]);
    const animationFrame = useRef<number>(0);
    const startTime = useRef<number>(0);

    useEffect(() => {
        if (active) {
            setShouldRender(true);
            startTime.current = Date.now();

            const canvas = canvasRef.current;
            if (!canvas) return;

            const rect = canvas.getBoundingClientRect();
            canvas.width = rect.width * devicePixelRatio;
            canvas.height = rect.height * devicePixelRatio;

            // Initialize particles
            particles.current = Array.from({ length: particleCount }).map(() => ({
                x: canvas.width / 2,
                y: canvas.height / 2,
                vx: (Math.random() - 0.5) * 30,
                vy: (Math.random() - 0.7) * 30,
                rotation: Math.random() * 360,
                vRotation: (Math.random() - 0.5) * 10,
                color: COLORS[Math.floor(Math.random() * COLORS.length)],
                size: Math.random() * 10 + 5,
                shape: Math.random() > 0.5 ? "circle" : "square",
            }));

            const animate = () => {
                const elapsed = Date.now() - startTime.current;
                if (elapsed > durationMs) {
                    setShouldRender(false);
                    onComplete?.();
                    return;
                }

                const ctx = canvas.getContext("2d");
                if (!ctx) return;

                ctx.clearRect(0, 0, canvas.width, canvas.height);

                particles.current.forEach((p) => {
                    p.x += p.vx;
                    p.y += p.vy;
                    p.vy += 0.8; // gravity
                    p.vx *= 0.98; // friction
                    p.rotation += p.vRotation;

                    ctx.fillStyle = p.color;
                    ctx.beginPath();
                    ctx.save();
                    ctx.translate(p.x, p.y);
                    ctx.rotate((p.rotation * Math.PI) / 180);

                    if (p.shape === "circle") {
                        ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
                    } else {
                        ctx.rect(-p.size / 2, -p.size / 2, p.size, p.size);
                    }

                    ctx.fill();
                    ctx.restore();
                });

                animationFrame.current = requestAnimationFrame(animate);
            };

            animationFrame.current = requestAnimationFrame(animate);
        } else {
            setShouldRender(false);
        }

        return () => {
            cancelAnimationFrame(animationFrame.current);
        };
    }, [active, durationMs, onComplete, particleCount]);

    if (!shouldRender) return null;

    return (
        <canvas
            ref={canvasRef}
            className="pointer-events-none fixed inset-0 z-[100] h-full w-full"
        />
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { Flame } from "lucide-react";
import { useEffect, useState } from "react";

interface JuicyStreakProps {
    count: number;
    className?: string;
}

/**
 * JuicyStreak: A dynamic streak counter that ignites as the count increases.
 * Includes "Juicy" physics-based feedback and celebratory particles.
 */
export default function JuicyStreak({ count, className = "" }: JuicyStreakProps) {
    const [isHot, setIsHot] = useState(false);

    useEffect(() => {
        if (count > 0) {
            setIsHot(true);
            const timer = setTimeout(() => setIsHot(false), 500);
            return () => clearTimeout(timer);
        }
    }, [count]);

    if (count <= 0) return null;

    const getIntensity = () => {
        if (count < 3) return "text-orange-400";
        if (count < 7) return "text-orange-500 shadow-orange-500/50";
        return "text-red-500 shadow-red-500/50";
    };

    return (
        <AnimatePresence>
            <motion.div
                initial={{ scale: 0, opacity: 0, rotate: -20 }}
                animate={{
                    scale: 1,
                    opacity: 1,
                    rotate: 0,
                    y: isHot ? -10 : 0
                }}
                exit={{ scale: 0, opacity: 0 }}
                className={`flex items-center gap-2 rounded-full border-2 bg-white px-4 py-2 shadow-lg dark:bg-stone-900 ${getIntensity()} ${className}`}
                style={{
                    borderColor: "currentColor",
                    boxShadow: count >= 5 ? "0 0 20px rgba(255, 69, 0, 0.2)" : "none"
                }}
            >
                <div className="relative">
                    <Flame className={`h-6 w-6 ${count >= 5 ? "animate-pulse" : ""}`} fill="currentColor" />

                    {count >= 3 && (
                        <motion.div
                            animate={{
                                scale: [1, 1.5, 1],
                                opacity: [0.5, 0, 0.5]
                            }}
                            transition={{ duration: 1, repeat: Infinity }}
                            className="absolute inset-0 bg-orange-400 blur-lg rounded-full"
                        />
                    )}
                </div>

                <div className="flex flex-col leading-none">
                    <span className="text-[10px] uppercase font-bold tracking-wider opacity-60">Streak</span>
                    <motion.span
                        key={count}
                        initial={{ scale: 1.5, filter: "blur(4px)" }}
                        animate={{ scale: 1, filter: "blur(0px)" }}
                        className="text-2xl font-black italic"
                    >
                        {count}
                    </motion.span>
                </div>

                {/* Celebration Particles */}
                {isHot && (
                    <div className="absolute inset-0 overflow-visible pointer-events-none">
                        {[...Array(6)].map((_, i) => (
                            <motion.div
                                key={i}
                                initial={{ x: 0, y: 0, scale: 1 }}
                                animate={{
                                    x: (i - 2.5) * 20,
                                    y: -40 - Math.random() * 40,
                                    scale: 0,
                                    rotate: Math.random() * 360
                                }}
                                className="absolute left-1/2 top-1/2 h-2 w-2 rounded-full bg-orange-400"
                            />
                        ))}
                    </div>
                )}
            </motion.div>
        </AnimatePresence>
    );
}

