"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMascot } from "@/components/experience/MascotHost";
import { JUICY_SPRINGS } from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { hapticSelection, hapticSuccess, hapticCelebration } from "@/lib/platform/haptics";
import { Box, Layers, MousePointer2, Eraser, Share2, Sparkles } from "lucide-react";

/* --- Cosmic Canvas Content --- */
type BlockType = "glass" | "gold" | "chrome" | "neon";
type Block = {
    id: number;
    type: BlockType;
    height: number;
};

const BLOCK_CONFIG: Record<BlockType, { color: string, label: string }> = {
    glass: { color: "bg-white/20 backdrop-blur-md border-white/30", label: "Frosted Glass" },
    gold: { color: "bg-amber-400 border-amber-500 shadow-[0_0_15px_rgba(251,191,36,0.5)]", label: "Aureum Gold" },
    chrome: { color: "bg-slate-300 border-slate-400 shadow-[inset_0_0_10px_rgba(255,255,255,0.8)]", label: "Mirror Chrome" },
    neon: { color: "bg-indigo-500 border-indigo-400 shadow-[0_0_20px_rgba(99,102,241,0.8)]", label: "Vivid Neon" }
};

export default function CosmicCanvas() {
    const { setMood, setMessage } = useMascot();
    const [grid, setGrid] = useState<(Block | null)[][]>(
        Array(8).fill(null).map(() => Array(8).fill(null))
    );
    const [activeBrush, setActiveBrush] = useState<BlockType>("glass");
    const [isErasing, setIsErasing] = useState(false);

    useEffect(() => {
        setMessage("Welcome to the Cosmic Canvas. Let's harmonize the spatial frequency of this galaxy! 🌙✨");
        setMood("happy");
    }, []);

    const handleGridClick = (r: number, c: number) => {
        if (isErasing) {
            if (grid[r][c]) {
                void hapticSelection();
                setGrid(prev => {
                    const next = prev.map(row => [...row]);
                    next[r][c] = null;
                    return next;
                });
            }
            return;
        }

        void hapticSuccess();
        setGrid(prev => {
            const next = prev.map(row => [...row]);
            const current = next[r][c];
            if (current && current.type === activeBrush) {
                if (current.height < 5) {
                    next[r][c] = { ...current, height: current.height + 1 };
                }
            } else {
                next[r][c] = { id: Math.random(), type: activeBrush, height: 1 };
            }
            return next;
        });

        if (Math.random() > 0.8) {
            setMood("happy");
            setMessage("A beautiful structural resonance! Keep building. 🏛️");
        }
    };

    const clearCanvas = () => {
        void hapticSelection();
        setGrid(Array(8).fill(null).map(() => Array(8).fill(null)));
        setMood("thinking");
        setMessage("A fresh start. The stars are ready for a new vision.");
    };

    return (
        <div className="relative min-h-[750px] w-full flex flex-col items-center justify-center p-8 bg-zinc-950 overflow-hidden rounded-[3rem] border-4 border-slate-900 shadow-2xl">
            {/* 4K Zen Background */}
            <div className="absolute inset-0 opacity-50">
                <img
                    src="/cosmic_canvas_zen_space_bg_1772427760520.png"
                    alt="Zen Space"
                    className="w-full h-full object-cover scale-110 blur-[1px]"
                />
            </div>

            {/* Floating Toolbar */}
            <div className="absolute top-8 left-8 flex flex-col gap-4 z-20">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black uppercase text-indigo-400 tracking-[0.4em]">Creative Sandbox</span>
                    <h2 className="text-4xl font-black italic text-white tracking-tighter">COSMIC CANVAS</h2>
                </div>

                <div className="bg-white/5 border border-white/10 p-2 rounded-3xl backdrop-blur-2xl flex flex-col gap-2">
                    {(Object.keys(BLOCK_CONFIG) as BlockType[]).map(type => (
                        <motion.button
                            key={type}
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                            onClick={() => {
                                setActiveBrush(type);
                                setIsErasing(false);
                                void hapticSelection();
                            }}
                            className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all border-2 
                                ${activeBrush === type && !isErasing ? "border-white bg-white/20 scale-110 shadow-lg" : "border-transparent bg-white/5 opacity-60"}`}
                        >
                            <div className={`w-6 h-6 rounded-lg ${BLOCK_CONFIG[type].color}`} />
                        </motion.button>
                    ))}
                    <div className="h-[1px] bg-white/10 my-1 mx-2" />
                    <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        onClick={() => {
                            setIsErasing(true);
                            void hapticSelection();
                        }}
                        className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all border-2
                            ${isErasing ? "border-rose-500 bg-rose-500/20 scale-110" : "border-transparent bg-white/5 opacity-60"}`}
                    >
                        <Eraser className="w-6 h-6 text-rose-400" />
                    </motion.button>
                </div>
            </div>

            {/* Interactive Grid Container - ISO VIEW */}
            <div className="relative z-10 w-full flex items-center justify-center perspective-[2000px]">
                <div
                    className="relative grid grid-cols-8 grid-rows-8 gap-1 p-2 bg-white/5 border border-white/10 rounded-2xl backdrop-blur-md rotate-x-[60deg] rotate-z-[45deg] transform-style-3d shadow-[0_50px_100px_rgba(0,0,0,0.5)]"
                    style={{ width: "450px", height: "450px" }}
                >
                    {grid.map((row, r) => row.map((block, c) => (
                        <div
                            key={`${r}-${c}`}
                            className="relative w-full h-full bg-white/5 border border-white/5 hover:bg-white/20 transition-colors cursor-pointer"
                            onClick={() => handleGridClick(r, c)}
                        >
                            <AnimatePresence>
                                {block && (
                                    <motion.div
                                        initial={{ scale: 0, y: 100 }}
                                        animate={{ scale: 1, y: 0 }}
                                        exit={{ scale: 0, opacity: 0 }}
                                        transition={JUICY_SPRINGS.stiff}
                                        className="absolute inset-0 transform-style-3d"
                                    >
                                        {/* 3D Visual Block Logic */}
                                        <div className="absolute inset-0 flex items-center justify-center">
                                            {[...Array(block.height)].map((_, i) => (
                                                <motion.div
                                                    key={i}
                                                    initial={{ z: 0 }}
                                                    animate={{ z: i * 20 }}
                                                    className={`absolute w-full h-full rounded-sm border-2 ${BLOCK_CONFIG[block.type].color} transform-translate-z-[${i * 20}px]`}
                                                    style={{ transform: `translateZ(${i * 20}px)` }}
                                                />
                                            ))}
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    )))}
                </div>
            </div>

            {/* Canvas Actions */}
            <div className="absolute bottom-12 flex gap-4 z-20">
                <PhysicalButton onClick={clearCanvas} className="bg-rose-500/20 text-rose-300 px-6 h-12 rounded-2xl text-xs font-black uppercase tracking-widest border border-rose-500/30">
                    WIPE GRID 🧹
                </PhysicalButton>
                <PhysicalButton onClick={() => void hapticCelebration()} className="bg-indigo-500 text-white px-8 h-12 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center gap-2">
                    <Share2 className="w-4 h-4" /> EXPORT GALAXY
                </PhysicalButton>
            </div>

            {/* Luna's Harmonic Feedback */}
            <div className="absolute top-10 right-10 flex items-center gap-4 opacity-40">
                <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Luna Logic</span>
                    <span className="text-[8px] font-medium text-slate-500">Aesthetic Frequency: 432Hz</span>
                </div>
                <div className="w-10 h-10 rounded-full border border-indigo-500/30 p-1">
                    <motion.div
                        animate={{ scale: [1, 1.2, 1], rotate: 360 }}
                        transition={{ duration: 4, repeat: Infinity, ease: "linear" }}
                        className="w-full h-full rounded-full bg-gradient-to-tr from-indigo-500 to-purple-500"
                    />
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    Compass,
    Map as MapIcon,
    Search,
    History,
    ChevronRight,
    Star,
    CheckCircle2,
    AlertCircle,
    ArrowLeft,
    Scroll,
    Globe,
    Camera
} from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSuccess, hapticSelection } from "@/lib/platform/haptics";
import MascotFriend from "../experience/KoydoMascotFriends";

/**
 * ECHO'S EXPEDITION - Phase 9 (Explorer Batch)
 * A 4K historical scavenger hunt with sequential map-based quests.
 * Theme: "Dora the Explorer" style interaction with premium aesthetics.
 */

interface QuestStep {
    id: string;
    title: string;
    instruction: string;
    x: number;
    y: number;
    targetId: string;
    hint: string;
}

const QUEST_STEPS: QuestStep[] = [
    {
        id: "start",
        title: "The Ancient Portal",
        instruction: "Welcome, Explorer! We need to locate the Rosetta Stone fragment. Look near the pyramid base.",
        x: 30,
        y: 60,
        targetId: "rosetta",
        hint: "It's a dark stone with mysterious writings."
    },
    {
        id: "temple",
        title: "Temple of Knowledge",
        instruction: "Great find! Now, we must identify the Great Library's symbol. Search the upper columns.",
        x: 70,
        y: 30,
        targetId: "scroll",
        hint: "Look for a symbol shaped like an ancient scroll."
    },
    {
        id: "artifact",
        title: "The Lost Amulet",
        instruction: "The final piece is hidden in the oasis. Find the Golden Ankh beneath the palm trees.",
        x: 50,
        y: 80,
        targetId: "ankh",
        hint: "It's shining bright gold in the sand."
    }
];

export default function EchosExpedition() {
    const [stepIndex, setStepIndex] = useState(0);
    const [foundItems, setFoundItems] = useState<string[]>([]);
    const [isComplete, setIsComplete] = useState(false);
    const [showHint, setShowHint] = useState(false);
    const [scannerPos, setScannerPos] = useState({ x: 0, y: 0 });
    const [isScanning, setIsScanning] = useState(false);

    const currentStep = QUEST_STEPS[stepIndex];

    const handleInteract = (e: React.MouseEvent | React.TouchEvent) => {
        if (isComplete) return;

        const bounds = e.currentTarget.getBoundingClientRect();
        const x = (('touches' in e) ? e.touches[0].clientX : (e as React.MouseEvent).clientX) - bounds.left;
        const y = (('touches' in e) ? e.touches[0].clientY : (e as React.MouseEvent).clientY) - bounds.top;

        const pctX = (x / bounds.width) * 100;
        const pctY = (y / bounds.height) * 100;

        setScannerPos({ x, y });
        setIsScanning(true);
        setTimeout(() => setIsScanning(false), 500);

        // Check if close to current target
        const dist = Math.sqrt(Math.pow(pctX - currentStep.x, 2) + Math.pow(pctY - currentStep.y, 2));

        if (dist < 5) {
            handleSuccess();
        } else {
            hapticSelection();
        }
    };

    const handleSuccess = useCallback(() => {
        hapticSuccess();
        setFoundItems(prev => [...prev, currentStep.targetId]);

        if (stepIndex < QUEST_STEPS.length - 1) {
            setStepIndex(prev => prev + 1);
            setShowHint(false);
        } else {
            setIsComplete(true);
        }
    }, [stepIndex, currentStep.targetId]);

    return (
        <div className="relative w-full aspect-video rounded-3xl overflow-hidden bg-slate-950 border border-white/10 shadow-2xl font-sans group">
            {/* 4K Background Environment (Cinematic Matte) */}
            <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1503177119275-0aa32b3a9368?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center brightness-50 opacity-60 mix-blend-overlay" />

            {/* Interactive Map Overlay */}
            <motion.div
                className="absolute inset-0 cursor-crosshair"
                onMouseDown={handleInteract}
                onTouchStart={handleInteract}
            >
                {/* Scanner Effect */}
                <AnimatePresence>
                    {isScanning && (
                        <motion.div
                            initial={{ scale: 0, opacity: 1 }}
                            animate={{ scale: 4, opacity: 0 }}
                            exit={{ opacity: 0 }}
                            className="absolute pointer-events-none w-20 h-20 border-2 border-blue-400/50 rounded-full"
                            style={{ left: scannerPos.x - 40, top: scannerPos.y - 40 }}
                        />
                    )}
                </AnimatePresence>

                {/* Hotspots (Hidden for exploration) */}
                {QUEST_STEPS.map((step, idx) => (
                    foundItems.includes(step.targetId) && (
                        <motion.div
                            key={step.id}
                            initial={{ scale: 0, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            className="absolute w-8 h-8 flex items-center justify-center"
                            style={{ left: `${step.x}%`, top: `${step.y}%`, transform: 'translate(-50%, -50%)' }}
                        >
                            <div className="absolute inset-0 bg-yellow-400/20 rounded-full animate-ping" />
                            <CheckCircle2 className="w-6 h-6 text-yellow-400" />
                        </motion.div>
                    )
                ))}
            </motion.div>

            {/* HUD: Left Column (Progress) */}
            <div className="absolute top-6 left-6 flex flex-col gap-3">
                <div className="px-4 py-2 bg-black/40 backdrop-blur-xl border border-white/10 rounded-2xl flex items-center gap-3">
                    <MapIcon className="w-5 h-5 text-blue-400" />
                    <span className="text-white font-medium">Expedition Map</span>
                </div>

                <div className="flex flex-col gap-2">
                    {QUEST_STEPS.map((step, idx) => (
                        <motion.div
                            key={step.id}
                            animate={{
                                opacity: idx <= stepIndex ? 1 : 0.4,
                                x: idx === stepIndex ? 10 : 0
                            }}
                            className={`px-4 py-2 rounded-xl flex items-center gap-3 border ${idx === stepIndex ? "bg-blue-500/20 border-blue-500/50" : "bg-black/40 border-white/10"
                                }`}
                        >
                            {foundItems.includes(step.targetId) ? (
                                <CheckCircle2 className="w-4 h-4 text-green-400" />
                            ) : idx === stepIndex ? (
                                <div className="w-4 h-4 rounded-full border-2 border-blue-400 border-t-transparent animate-spin" />
                            ) : (
                                <div className="w-4 h-4 rounded-full border-2 border-white/20" />
                            )}
                            <span className="text-sm text-white/80 font-medium">{step.title}</span>
                        </motion.div>
                    ))}
                </div>
            </div>

            {/* HUD: Mascot Interactive Guidance (Dora Style) */}
            <div className="absolute bottom-6 left-6 right-6 flex flex-col gap-4">
                <AnimatePresence mode="wait">
                    {!isComplete && (
                        <motion.div
                            key={stepIndex}
                            initial={{ y: 20, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            exit={{ y: -20, opacity: 0 }}
                            className="bg-black/60 backdrop-blur-2xl border border-white/10 rounded-3xl p-6 flex gap-6 items-center"
                        >
                            <div className="w-24 h-24 relative flex-shrink-0">
                                <MascotFriend id="echo" size="lg" mood={showHint ? "thinking" : "happy"} />
                            </div>

                            <div className="flex-grow">
                                <h3 className="text-blue-400 font-bold text-lg mb-1 flex items-center gap-2">
                                    <Compass className="w-5 h-5" />
                                    Expedition Guide
                                </h3>
                                <p className="text-white/90 text-xl leading-relaxed">
                                    {showHint ? currentStep.hint : currentStep.instruction}
                                </p>
                            </div>

                            <button
                                onClick={() => {
                                    hapticSelection();
                                    setShowHint(!showHint);
                                }}
                                className={`px-6 py-3 rounded-2xl font-bold transition-all flex items-center gap-2 ${showHint ? "bg-white text-slate-900" : "bg-blue-500 text-white"
                                    } shadow-lg shadow-blue-500/20 hover:scale-105 active:scale-95`}
                            >
                                <Search className="w-5 h-5" />
                                {showHint ? "Hide Hint" : "Get Hint"}
                            </button>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Win Screen */}
            <AnimatePresence>
                {isComplete && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 bg-slate-900/90 backdrop-blur-3xl flex items-center justify-center p-12 z-50 text-center"
                    >
                        <motion.div
                            initial={{ scale: 0.8, y: 20 }}
                            animate={{ scale: 1, y: 0 }}
                            className="max-w-md w-full"
                        >
                            <div className="w-32 h-32 mx-auto mb-8">
                                <MascotFriend id="echo" size="xl" mood="happy" />
                            </div>

                            <div className="inline-flex p-3 bg-yellow-500/20 rounded-2xl mb-6">
                                <Globe className="w-8 h-8 text-yellow-400" />
                            </div>

                            <h2 className="text-5xl font-black text-white mb-4 italic tracking-tight uppercase">
                                Expedition <br /> Complete!
                            </h2>

                            <p className="text-white/60 text-lg mb-8">
                                You've archived the fragments of history. Your legacy is secured in the 4K archives.
                            </p>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="p-4 bg-white/5 border border-white/10 rounded-2xl">
                                    <div className="text-2xl font-bold text-white tracking-widest uppercase mb-1">3 / 3</div>
                                    <div className="text-xs text-blue-400 font-bold uppercase tracking-tighter">Artifacts Found</div>
                                </div>
                                <div className="p-4 bg-white/5 border border-white/10 rounded-2xl">
                                    <div className="text-2xl font-bold text-white tracking-widest uppercase mb-1">4K</div>
                                    <div className="text-xs text-blue-400 font-bold uppercase tracking-tighter">Resolution</div>
                                </div>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Cinematic Overlay - Grain & Vignette */}
            <div className="absolute inset-0 pointer-events-none bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-80" />
            <div className="absolute inset-0 pointer-events-none opacity-[0.03] mix-blend-overlay bg-[url('https://grainy-gradients.vercel.app/noise.svg')]" />
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Zap, Sun, Wind, Battery, Activity, ShieldCheck, Thermometer, Info, ChevronRight, Leaf, Trash2, CloudRain } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Sustainability Types --- */
type EnergySource = "SOLAR" | "WIND" | "COAL" | "NUCLEAR";

type GameStats = {
    power: number;
    carbon: number;
    budget: number;
    happiness: number;
};

export default function EcoEngineer() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "GRID" | "CRISIS" | "STABLE">("IDLE");
    const [sources, setSources] = useState<Record<EnergySource, number>>({
        SOLAR: 0,
        WIND: 0,
        COAL: 2,
        NUCLEAR: 0
    });
    const [stats, setStats] = useState<GameStats>({
        power: 40,
        carbon: 80,
        budget: 5000,
        happiness: 50
    });

    const updateSimulation = useCallback(() => {
        if (gameState !== "GRID") return;

        setStats(prev => {
            const powerGen = (sources.SOLAR * 10) + (sources.WIND * 15) + (sources.COAL * 25) + (sources.NUCLEAR * 50);
            const carbonGen = (sources.COAL * 5) - (sources.SOLAR * 1) - (sources.WIND * 2);

            return {
                ...prev,
                power: Math.min(100, powerGen),
                carbon: Math.max(0, Math.min(100, prev.carbon + carbonGen * 0.1)),
                happiness: Math.min(100, Math.max(0, prev.happiness + (powerGen > 60 ? 0.5 : -0.5) - (prev.carbon > 70 ? 0.5 : 0)))
            };
        });

    }, [gameState, sources]);

    useEffect(() => {
        const interval = setInterval(updateSimulation, 1000);
        return () => clearInterval(interval);
    }, [updateSimulation]);

    const buildSource = (type: EnergySource) => {
        const costs: Record<EnergySource, number> = { SOLAR: 500, WIND: 800, COAL: 300, NUCLEAR: 2500 };
        if (stats.budget >= costs[type]) {
            setSources(prev => ({ ...prev, [type]: prev[type] + 1 }));
            setStats(s => ({ ...s, budget: s.budget - costs[type] }));
            hapticSelection();

            if (type === "SOLAR" || type === "WIND") {
                setMessage(`Investing in ${type.toLowerCase()} energy. The sky is our battery! ☀️`);
                setMood("happy");
            }
        } else {
            hapticError();
            setMessage("Insufficient funds for this infrastructure. 💸");
        }
    };

    const decommissionSource = (type: EnergySource) => {
        if (sources[type] > 0) {
            setSources(prev => ({ ...prev, [type]: prev[type] - 1 }));
            hapticSelection();
        }
    };

    const startGrid = () => {
        setGameState("GRID");
        setMood("thinking");
        setMessage("Energy grid online. Transition the city to 100% renewables while keeping the lights on! ⚡");
        hapticSuccess();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-slate-950 rounded-[4rem] border border-emerald-500/20 overflow-hidden shadow-2xl flex flex-col font-sans">
            {/* Eco Background */}
            <div className="absolute inset-0 z-0 opacity-20 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(52,211,153,0.1)_0%,transparent_70%)]" />
                <svg className="absolute inset-0 w-full h-full text-emerald-500/5">
                    <pattern id="eco-grid" x="0" y="0" width="60" height="60" patternUnits="userSpaceOnUse">
                        <circle cx="30" cy="30" r="2" fill="currentColor" />
                    </pattern>
                    <rect width="100%" height="100%" fill="url(#eco-grid)" />
                </svg>
            </div>

            {/* HUD */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-zinc-900/60 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-emerald-500/10 border border-emerald-500/30 flex items-center justify-center">
                        <Leaf className="text-emerald-400 w-8 h-8" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Eco Engineer</h2>
                        <span className="text-[10px] font-bold text-emerald-600 uppercase tracking-widest">Sustain-Grid v3.0</span>
                    </div>
                </div>

                <div className="flex gap-6">
                    <StatBox label="Carbon Footprint" value={stats.carbon} color={stats.carbon > 60 ? "text-rose-400" : "text-emerald-400"} />
                    <StatBox label="Grid Power" value={stats.power} color="text-sky-400" unit="MW" />
                    <StatBox label="Citizen Mood" value={stats.happiness} color="text-amber-400" />
                    <div className="bg-white/5 border border-white/5 px-6 py-3 rounded-2xl flex flex-col items-end min-w-[140px]">
                        <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">BUDGET</span>
                        <span className="text-xl font-black italic text-emerald-400 tabular-nums">${stats.budget}</span>
                    </div>
                </div>
            </div>

            {/* Grid Workspace */}
            <div className="relative z-10 flex-1 flex">
                {/* Left: Infrastructure Panel */}
                <div className="w-80 border-r border-white/5 p-8 flex flex-col gap-4 bg-zinc-900/40">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-4">Construction Menu</h3>
                    <InfraCard
                        type="SOLAR"
                        count={sources.SOLAR}
                        cost={500}
                        icon={Sun}
                        color="text-amber-400"
                        onBuild={() => buildSource("SOLAR")}
                        onDec={() => decommissionSource("SOLAR")}
                    />
                    <InfraCard
                        type="WIND"
                        count={sources.WIND}
                        cost={800}
                        icon={Wind}
                        color="text-sky-400"
                        onBuild={() => buildSource("WIND")}
                        onDec={() => decommissionSource("WIND")}
                    />
                    <InfraCard
                        type="NUCLEAR"
                        count={sources.NUCLEAR}
                        cost={2500}
                        icon={Activity}
                        color="text-purple-400"
                        onBuild={() => buildSource("NUCLEAR")}
                        onDec={() => decommissionSource("NUCLEAR")}
                    />
                    <div className="mt-auto pt-8 border-t border-white/5">
                        <InfraCard
                            type="COAL"
                            count={sources.COAL}
                            cost={300}
                            icon={Trash2}
                            color="text-zinc-500"
                            onBuild={() => buildSource("COAL")}
                            onDec={() => decommissionSource("COAL")}
                        />
                    </div>
                </div>

                {/* Right: Simulation View */}
                <div className="flex-1 p-12 flex flex-col items-center justify-center relative bg-zinc-950/20">
                    {/* Skyline Visualizer */}
                    <div className="relative w-full max-w-2xl h-80 bg-zinc-900/40 rounded-[3rem] border border-white/5 overflow-hidden shadow-inner flex items-end justify-center px-12 gap-4">
                        {/* Atmosphere Color */}
                        <div className={`absolute inset-0 transition-colors duration-1000 ${stats.carbon > 70 ? 'bg-zinc-800/40' : stats.carbon > 40 ? 'bg-emerald-950/20' : 'bg-sky-900/10'}`} />

                        <AnimatePresence>
                            {/* Wind Turbines */}
                            {Array.from({ length: sources.WIND }).map((_, i) => (
                                <motion.div
                                    key={`wind-${i}`}
                                    {...JUICY_VARIANTS.slideUp}
                                    className="relative h-40 w-8 flex flex-col items-center"
                                >
                                    <motion.div
                                        animate={{ rotate: 360 }}
                                        transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
                                        className="h-12 w-12 border-2 border-white/20 rounded-full flex items-center justify-center"
                                    >
                                        <div className="w-1 h-12 bg-white/20 absolute rotate-0" />
                                        <div className="w-1 h-12 bg-white/20 absolute rotate-60" />
                                        <div className="w-1 h-12 bg-white/20 absolute rotate-120" />
                                    </motion.div>
                                    <div className="w-1 h-full bg-white/10" />
                                </motion.div>
                            ))}

                            {/* Solar Panels */}
                            {Array.from({ length: sources.SOLAR }).map((_, i) => (
                                <motion.div
                                    key={`solar-${i}`}
                                    {...JUICY_VARIANTS.slideUp}
                                    className="h-16 w-16 bg-blue-500/20 border-2 border-blue-400/40 rounded-xl mb-4"
                                />
                            ))}

                            {/* Coal Plants */}
                            {Array.from({ length: sources.COAL }).map((_, i) => (
                                <motion.div
                                    key={`coal-${i}`}
                                    {...JUICY_VARIANTS.slideUp}
                                    className="relative h-48 w-24 bg-zinc-800 border-2 border-zinc-700 rounded-t-2xl flex flex-col items-center"
                                >
                                    <motion.div
                                        animate={{ y: [-10, -50], opacity: [0.5, 0] }}
                                        transition={{ duration: 2, repeat: Infinity }}
                                        className="absolute -top-12 w-8 h-8 bg-zinc-500/40 blur-xl rounded-full"
                                    />
                                    <div className="mt-4 text-[8px] font-black text-zinc-600 uppercase tracking-widest">COAL-X</div>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>

                    {/* Progress Gauge */}
                    <div className="mt-12 w-full max-w-sm">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Renewable Mastery</span>
                            <span className="text-xs font-black text-emerald-400">{((sources.SOLAR + sources.WIND) / Math.max(1, sources.SOLAR + sources.WIND + sources.COAL) * 100).toFixed(0)}%</span>
                        </div>
                        <div className="h-3 bg-white/5 rounded-full overflow-hidden border border-white/5 p-0.5">
                            <motion.div
                                className="h-full bg-gradient-to-r from-emerald-600 to-sky-400 rounded-full"
                                animate={{ width: `${(sources.SOLAR + sources.WIND) / Math.max(1, sources.SOLAR + sources.WIND + sources.COAL) * 100}%` }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Start Overlay */}
            {gameState === "IDLE" && (
                <motion.div
                    {...JUICY_VARIANTS.slideUp}
                    className="absolute inset-0 z-40 bg-zinc-950/90 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                >
                    <div className="w-24 h-24 bg-emerald-500/20 rounded-[2.5rem] flex items-center justify-center border border-emerald-500/30 mb-8 overflow-hidden group">
                        <Zap className="w-12 h-12 text-emerald-400 group-hover:scale-110 transition-transform" />
                    </div>
                    <h3 className="text-5xl font-black italic tracking-tighter text-white mb-4 uppercase leading-none">Power the Future</h3>
                    <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                        The city relies on you. Transition to green energy, manage your budget, and reduce carbon emissions in 4K resolution.
                    </p>
                    <PhysicalButton
                        onClick={startGrid}
                        className="bg-emerald-600 h-24 px-20 rounded-[3rem] text-2xl"
                    >
                        BOOT SYSTEM ⚡
                    </PhysicalButton>
                </motion.div>
            )}
        </div>
    );
}

function StatBox({ label, value, color, unit = "%" }: { label: string, value: number, color: string, unit?: string }) {
    return (
        <div className="bg-white/5 border border-white/5 px-6 py-3 rounded-2xl flex flex-col items-end min-w-[140px]">
            <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">{label}</span>
            <div className="flex items-baseline gap-1">
                <span className={`text-xl font-black italic tabular-nums ${color}`}>{value.toFixed(0)}</span>
                <span className="text-[10px] font-bold text-zinc-600">{unit}</span>
            </div>
        </div>
    );
}

function InfraCard({ type, count, cost, icon: Icon, color, onBuild, onDec }: any) {
    return (
        <div className="bg-white/5 border border-white/5 p-5 rounded-3xl flex flex-col gap-4 group hover:bg-zinc-800/60 transition-all">
            <div className="flex justify-between items-start">
                <div className={`p-3 rounded-xl bg-zinc-800 border border-white/5 ${color}`}>
                    <Icon className="w-5 h-5" />
                </div>
                <div className="flex flex-col items-end">
                    <span className="text-[8px] font-black text-zinc-600 uppercase tracking-widest">Active Units</span>
                    <span className="text-lg font-black text-white tabular-nums">{count}</span>
                </div>
            </div>
            <div className="flex justify-between items-center">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black text-white uppercase tracking-tighter">{type}</span>
                    <span className="text-[9px] font-bold text-emerald-500/60">${cost}</span>
                </div>
                <div className="flex gap-2">
                    <button onClick={onDec} className="w-8 h-8 rounded-lg bg-zinc-700 flex items-center justify-center hover:bg-zinc-600 text-white">-</button>
                    <button onClick={onBuild} className="w-12 h-8 rounded-lg bg-emerald-600 flex items-center justify-center hover:bg-emerald-500 text-white text-xs font-black">+</button>
                </div>
            </div>
        </div>
    );
}

