"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMascot } from "@/components/experience/MascotHost";
import { JUICY_VARIANTS, JUICY_SPRINGS, EXPERIENCE_COLORS } from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import JuicyStreak from "@/components/experience/JuicyStreak";
import { hapticSuccess, hapticCelebration, hapticSelection } from "@/lib/platform/haptics";
import { Flame, Beaker, Hammer, Star } from "lucide-react";

/* --- Fraction Forge Logic --- */
type Ingot = {
    target: number; // e.g. 0.75 for 3/4
    current: number;
    fractions: number[]; // e.g. [0.25, 0.5, 0.125]
};

export default function FractionForge() {
    const { setMood, setMessage } = useMascot();
    const [target, setTarget] = useState(0.75);
    const [current, setCurrent] = useState(0);
    const [options, setOptions] = useState([0.25, 0.5, 0.125]);
    const [streak, setStreak] = useState(0);
    const [phase, setPhase] = useState<"forging" | "success" | "exploding">("forging");

    useEffect(() => {
        setMessage("Welcome to the Fraction Forge! Let's mix some magical alloys! 🔥");
        setMood("happy");
        generateChallenge();
    }, []);

    const generateChallenge = () => {
        const possibleFractions = [0.25, 0.5, 0.125, 0.33, 0.66];
        const t = 0.5 + Math.random() * 0.4;
        setTarget(parseFloat(t.toFixed(2)));
        setCurrent(0);
        setOptions(possibleFractions.sort(() => Math.random() - 0.5).slice(0, 3));
        setPhase("forging");
    };

    const addAlloy = (val: number) => {
        if (phase !== "forging") return;

        const next = parseFloat((current + val).toFixed(2));
        void hapticSelection();

        if (next > target + 0.05) {
            handleExplosion();
        } else if (Math.abs(next - target) < 0.05) {
            setCurrent(next);
            handleSuccess();
        } else {
            setCurrent(next);
        }
    };

    const handleSuccess = () => {
        setPhase("success");
        setStreak(prev => prev + 1);
        setMood("happy");
        setMessage("A perfect Ingot! You're a Master Smith! 🔨✨");
        void hapticCelebration();

        setTimeout(() => {
            generateChallenge();
        }, 2500);
    };

    const handleExplosion = () => {
        setPhase("exploding");
        setStreak(0);
        setMood("thinking");
        setMessage("Too much heat! The alloy is unstable! 🌋");

        setTimeout(() => {
            generateChallenge();
        }, 2000);
    };

    const fillPercent = Math.min((current / target) * 100, 100);

    return (
        <div className="relative min-h-[600px] w-full flex flex-col items-center justify-center p-8 bg-stone-950 overflow-hidden rounded-[3rem] border-4 border-orange-950 shadow-2xl">
            {/* Forge Heat Background */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_bottom,_var(--tw-gradient-stops))] from-orange-500/20 via-transparent to-transparent opacity-50" />

            {/* Header */}
            <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10">
                <div className="flex flex-col">
                    <span className="text-xs font-black uppercase text-orange-500 tracking-[0.2em]">Magical Smithy</span>
                    <h2 className="text-4xl font-black italic text-white leading-none">FRACTION FORGE</h2>
                </div>
                <JuicyStreak count={streak} />
            </div>

            {/* The Crucible (Ingot Mold) */}
            <div className="relative w-48 h-64 mb-12 flex items-end justify-center">
                {/* Mold Frame */}
                <div className="absolute inset-0 border-x-4 border-b-4 border-stone-800 rounded-b-3xl" />

                {/* Molten Metal */}
                <motion.div
                    initial={{ height: 0 }}
                    animate={{ height: `${fillPercent}%` }}
                    transition={JUICY_SPRINGS.heavy}
                    className={`w-full rounded-b-2xl bg-gradient-to-t ${phase === "exploding" ? "from-red-600 to-yellow-400" : "from-orange-600 to-amber-300"
                        } relative`}
                >
                    {/* Liquid Sparkles */}
                    <div className="absolute inset-0 bg-white/10 opacity-30 mix-blend-overlay animate-pulse" />

                    {/* Heat Distortion */}
                    <motion.div
                        animate={{ y: [0, -5, 0] }}
                        transition={{ duration: 0.5, repeat: Infinity }}
                        className="absolute -top-1 left-0 right-0 h-2 bg-white/40 blur-sm"
                    />
                </motion.div>

                {/* Target Line */}
                <div className="absolute bottom-[100%] left-0 right-0 border-t-2 border-dashed border-white/50 flex justify-end">
                    <span className="text-[10px] bg-white/20 px-2 rounded-full absolute -top-3 text-white font-bold">TARGET: {target}</span>
                </div>

                {/* Glow Effect */}
                <div className={`absolute -inset-4 rounded-3xl blur-2xl transition-opacity duration-1000 ${phase === "success" ? "bg-amber-400/30 opacity-100" : "bg-orange-500/10 opacity-30"
                    }`} />
            </div>

            {/* Alloy Selection */}
            <div className="grid grid-cols-3 gap-6 z-10">
                {options.map((val, idx) => (
                    <motion.button
                        key={idx}
                        variants={JUICY_VARIANTS.pressable}
                        initial="initial"
                        whileHover="hover"
                        whileTap="tap"
                        onClick={() => addAlloy(val)}
                        disabled={phase !== "forging"}
                    >
                        <div className="flex flex-col items-center gap-2 p-4 bg-stone-900 border border-white/10 rounded-2xl shadow-xl hover:border-orange-500/50 transition-colors">
                            <Beaker className="text-orange-400 w-8 h-8" />
                            <span className="text-2xl font-black text-white">{val}</span>
                            <span className="text-[10px] text-stone-500 uppercase font-black">Add Alloy</span>
                        </div>
                    </motion.button>
                ))}
            </div>

            {/* Bottom UI */}
            <div className="mt-8 flex gap-4 items-center mb-4">
                <PhysicalButton
                    onClick={() => setCurrent(0)}
                    disabled={phase !== "forging"}
                    className="bg-stone-800 text-stone-400 text-xs px-4"
                >
                    PURGE CRUCIBLE 💀
                </PhysicalButton>

                <div className="flex items-center gap-2 bg-orange-950/30 border border-orange-500/20 px-4 py-2 rounded-xl">
                    <Hammer className="text-orange-500 w-4 h-4" />
                    <span className="text-xs font-bold text-orange-200">Forging at {Math.round(current * 100)}% density</span>
                </div>
            </div>

            {/* Success Overlay */}
            <AnimatePresence>
                {phase === "success" && (
                    <motion.div
                        initial={{ scale: 0.5, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        exit={{ scale: 1.5, opacity: 0 }}
                        className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex flex-col items-center pointer-events-none z-50"
                    >
                        <div className="bg-amber-400 text-black px-8 py-4 rounded-full text-4xl font-black italic shadow-[0_0_50px_rgba(251,191,36,0.6)]">
                            GOLDEN INGOT! 🏆
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    Zap,
    Atom,
    Activity,
    Shield,
    Thermometer,
    Settings,
    Gauge,
    Flame
} from "lucide-react";
import { hapticSuccess, hapticSelection, hapticWarning } from "@/lib/platform/haptics";
import MascotFriend from "../experience/KoydoMascotFriends";

/**
 * FUSION FOUNDER - Phase 10 (Advanced Engineering)
 * A 4K high-fidelity nuclear physics simulator.
 * Mechanic: Stabilize the fusion core by balancing magnetic containment.
 */

export default function FusionFounder() {
    const [gameState, setGameState] = useState<"playing" | "success">("playing");
    const [containment, setContainment] = useState(50);
    const [temperature, setTemperature] = useState(100);
    const [isSuccess, setIsSuccess] = useState(false);

    const handleContainmentChange = (val: number) => {
        setContainment(val);
        // Temperature is a function of containment (sweet spot at 85-95)
        const newTemp = 50 + (val * 1.5);
        setTemperature(newTemp);
        hapticSelection();

        if (val > 88 && val < 94) {
            handleComplete();
        } else if (val > 95) {
            hapticWarning();
        }
    };

    const handleComplete = () => {
        hapticSuccess();
        setIsSuccess(true);
    };

    return (
        <div className="relative w-full aspect-video rounded-[3rem] overflow-hidden bg-[#020617] border border-cyan-500/20 shadow-2xl font-sans group">
            {/* 4K Reactor Core Background */}
            <div className="absolute inset-0 opacity-40 bg-[url('https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&q=80&w=2000')] bg-cover" />
            <div className="absolute inset-0 bg-gradient-to-br from-cyan-950/80 via-transparent to-blue-950/80 pointer-events-none" />

            {/* HUD */}
            <div className="absolute inset-0 p-12 flex flex-col justify-between">
                <div className="flex justify-between items-start">
                    <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="flex flex-col gap-2">
                        <div className="flex items-center gap-3 text-cyan-400">
                            <Atom className="w-6 h-6 animate-spin-slow" />
                            <span className="font-black uppercase tracking-[0.4em] text-xs">Reactor Management</span>
                        </div>
                        <h1 className="text-5xl font-black text-white italic tracking-tighter uppercase leading-none">
                            Fusion <br /> Founder
                        </h1>
                    </motion.div>

                    <div className="flex gap-4">
                        <div className="px-6 py-4 bg-white/5 backdrop-blur-3xl rounded-2xl border border-white/10 flex flex-col items-end">
                            <span className="text-white/40 text-[10px] font-black uppercase tracking-widest">Temperature</span>
                            <span className={`text-2xl font-mono font-black ${temperature > 180 ? "text-rose-400" : temperature > 150 ? "text-amber-400" : "text-cyan-400"}`}>
                                {temperature.toFixed(1)} MK
                            </span>
                        </div>
                    </div>
                </div>

                {/* Core Visualization */}
                <div className="flex-grow flex items-center justify-center relative">
                    <div className="relative w-64 h-64 flex items-center justify-center">
                        {/* Magnetic Fields */}
                        <motion.div
                            animate={{
                                scale: [1, 1.1, 1],
                                rotate: 360,
                                opacity: containment / 100
                            }}
                            transition={{ duration: 4, repeat: Infinity, ease: "linear" }}
                            className="absolute inset-0 border-4 border-dashed border-cyan-400/30 rounded-full"
                        />
                        <motion.div
                            animate={{
                                scale: [1.2, 1, 1.2],
                                rotate: -360,
                                opacity: containment / 150
                            }}
                            transition={{ duration: 6, repeat: Infinity, ease: "linear" }}
                            className="absolute inset-0 border-2 border-dashed border-blue-400/20 rounded-full p-8"
                        />

                        {/* Plasma Core */}
                        <motion.div
                            animate={{
                                scale: 0.5 + (temperature / 400),
                                backgroundColor: temperature > 180 ? "#fb7185" : temperature > 150 ? "#fbbf24" : "#22d3ee"
                            }}
                            className="w-32 h-32 rounded-full blur-2xl relative z-10 shadow-[0_0_100px_rgba(34,211,238,0.5)]"
                        />
                        <motion.div
                            animate={{
                                scale: 0.2 + (temperature / 800),
                                opacity: [0.8, 1, 0.8]
                            }}
                            className="absolute w-16 h-16 bg-white rounded-full blur-xl z-20"
                        />

                        {/* Particle Ring */}
                        {[...Array(12)].map((_, i) => (
                            <motion.div
                                key={i}
                                animate={{
                                    rotate: 360,
                                }}
                                transition={{ duration: 2, repeat: Infinity, ease: "linear", delay: i * 0.1 }}
                                className="absolute inset-0"
                            >
                                <div className="w-2 h-2 bg-white rounded-full absolute top-0 left-1/2 -translate-x-1/2 blur-[1px]" />
                            </motion.div>
                        ))}
                    </div>

                    {/* Scanning Text */}
                    <div className="absolute bottom-0 inset-x-0 flex justify-center pb-8">
                        <div className="flex items-center gap-12 font-mono text-[10px] text-white/40">
                            <span className="flex items-center gap-2">
                                <Shield className="w-3 h-3 text-cyan-400" />
                                CONTAINMENT: {containment}%
                            </span>
                            <span className="flex items-center gap-2">
                                <Zap className="w-3 h-3 text-amber-400" />
                                OUTPUT: {(temperature * 1.2).toFixed(0)} GW
                            </span>
                        </div>
                    </div>
                </div>

                {/* Interaction Footer */}
                <div className="flex items-end justify-between">
                    <div className="w-1/2 flex flex-col gap-6">
                        <div className="flex flex-col gap-4">
                            <div className="flex justify-between items-center pr-4">
                                <span className="text-cyan-400/60 font-black uppercase tracking-widest text-[10px]">Magnetic Pressure</span>
                                <span className="text-white/40 font-mono text-[10px] italic">Target: 90.0% - 93.0%</span>
                            </div>
                            <input
                                type="range"
                                min="0"
                                max="100"
                                value={containment}
                                onChange={(e) => handleContainmentChange(Number(e.target.value))}
                                className="w-full h-3 bg-cyan-950/50 rounded-full appearance-none cursor-pointer accent-cyan-400"
                            />
                        </div>
                        <p className="text-white/30 text-xs font-mono italic">
                            Stabilize the deuterium-tritium plasma core using magnetohydrodynamic pressure.
                            Warning: Critical thermal excursion beyond 200 MK.
                        </p>
                    </div>

                    <div className="flex items-center gap-8">
                        <div className="w-16 h-16">
                            <MascotFriend id="spark" size="md" mood={isSuccess ? "happy" : temperature > 180 ? "surprised" : "thinking"} />
                        </div>
                        <div className="flex flex-col items-end">
                            <span className="text-white/20 text-[10px] font-black uppercase tracking-widest mb-2">Simulation State</span>
                            <div className={`px-8 py-4 rounded-2xl border-2 backdrop-blur-3xl font-black italic uppercase tracking-widest transition-all ${isSuccess ? "bg-emerald-500/10 border-emerald-400 text-emerald-400 shadow-[0_0_30px_rgba(52,211,153,0.3)]" :
                                    temperature > 180 ? "bg-rose-500/10 border-rose-400 text-rose-400 shadow-[0_0_30px_rgba(251,113,133,0.3)] animate-pulse" :
                                        "bg-cyan-500/10 border-cyan-400 text-cyan-400"
                                }`}>
                                {isSuccess ? "Ignition" : temperature > 180 ? "Danger" : "Reacting"}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Success Overlay */}
            <AnimatePresence>
                {isSuccess && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 bg-slate-950/95 backdrop-blur-2xl z-50 flex items-center justify-center p-12 text-center"
                    >
                        <motion.div
                            initial={{ scale: 0.9, y: 20 }}
                            animate={{ scale: 1, y: 0 }}
                            className="max-w-md"
                        >
                            <div className="w-40 h-40 mx-auto mb-8">
                                <MascotFriend id="spark" size="xl" mood="happy" />
                            </div>
                            <h2 className="text-6xl font-black text-white italic uppercase tracking-tighter mb-4">
                                Fusion <br /> Ignited!
                            </h2>
                            <p className="text-cyan-300/60 mb-10 text-lg">
                                You've maintained a stable magnetic bottle. Net energy gain achieved.
                                Infinite power for the experience hub unlocked!
                            </p>
                            <button
                                onClick={() => setIsSuccess(false)}
                                className="w-full py-5 bg-cyan-400 text-slate-950 rounded-3xl font-black uppercase tracking-widest shadow-2xl shadow-cyan-500/40 active:scale-95 transition-all outline-none"
                            >
                                stabilize next core
                            </button>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

