                                    }}
                                    className={`flex-shrink-0 w-16 h-16 rounded-xl border-2 flex items-center justify-center transition-all
                                    ${cmd.type === 'MOVE' ? 'bg-fuchsia-500/10' : cmd.type.startsWith('TURN') ? 'bg-indigo-500/10' : 'bg-zinc-800'}`}
