"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMascot } from "@/components/experience/MascotHost";
import { JUICY_VARIANTS, JUICY_SPRINGS } from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import JuicyStreak from "@/components/experience/JuicyStreak";
import { hapticSuccess, hapticSelection, hapticCelebration } from "@/lib/platform/haptics";
import { Cpu, Terminal, Square, Circle, Triangle } from "lucide-react";

/* --- Logical Link Content --- */
type Gate = {
    id: number;
    type: "AND" | "OR" | "NOT" | "XOR" | "NAND";
    color: string;
    icon: any;
};

const GATE_TYPES: Omit<Gate, "id">[] = [
    { type: "AND", color: "bg-cyan-500", icon: Square },
    { type: "OR", color: "bg-magenta-500", icon: Circle },
    { type: "XOR", color: "bg-amber-400", icon: Triangle },
    { type: "NOT", color: "bg-rose-500", icon: Cpu },
    { type: "NAND", color: "bg-emerald-500", icon: Terminal },
];

export default function LogicalLink() {
    const { setMood, setMessage } = useMascot();
    const [grid, setGrid] = useState<Gate[][]>([]);
    const [score, setScore] = useState(0);
    const [streak, setStreak] = useState(0);

    const initializeGrid = () => {
        const newGrid: Gate[][] = [];
        for (let r = 0; r < 6; r++) {
            newGrid[r] = [];
            for (let c = 0; c < 6; c++) {
                newGrid[r][c] = {
                    id: Math.random(),
                    ...GATE_TYPES[Math.floor(Math.random() * GATE_TYPES.length)]
                };
            }
        }
        setGrid(newGrid);
    };

    useEffect(() => {
        initializeGrid();
        setMessage("Welcome to Logical Link. Match synchronous gates to stabilize the digital core! 🤖🔌");
        setMood("happy");
    }, []);

    const handleTileClick = (r: number, c: number) => {
        void hapticSelection();
        const type = grid[r][c].type;

        // Find connected neighbors of same type
        const connected: { r: number, c: number }[] = [];
        const queue = [{ r, c }];
        const visited = new Set<string>();
        visited.add(`${r},${c}`);

        while (queue.length > 0) {
            const current = queue.shift()!;
            connected.push(current);

            const neighbors = [
                { r: current.r - 1, c: current.c },
                { r: current.r + 1, c: current.c },
                { r: current.r, c: current.c - 1 },
                { r: current.r, c: current.c + 1 },
            ];

            for (const n of neighbors) {
                if (n.r >= 0 && n.r < 6 && n.c >= 0 && n.c < 6 && !visited.has(`${n.r},${n.c}`) && grid[n.r][n.c].type === type) {
                    visited.add(`${n.r},${n.c}`);
                    queue.push(n);
                }
            }
        }

        if (connected.length >= 3) {
            // Match found!
            void hapticSuccess();
            setScore(prev => prev + connected.length * 10);
            setStreak(prev => prev + 1);

            setGrid(prev => {
                const newGrid = prev.map(row => [...row]);
                connected.forEach(p => {
                    newGrid[p.r][p.c] = {
                        id: Math.random(),
                        ...GATE_TYPES[Math.floor(Math.random() * GATE_TYPES.length)]
                    };
                });
                return newGrid;
            });

            if (connected.length >= 5) {
                void hapticCelebration();
                setMood("happy");
                setMessage(`Circuit overflow! You matched ${connected.length} gates! ⚡✨`);
            }
        }
    };

    return (
        <div className="relative min-h-[700px] w-full flex flex-col items-center justify-center p-8 bg-black overflow-hidden rounded-[3rem] border-4 border-slate-900 shadow-2xl">
            {/* 4K Background */}
            <div className="absolute inset-0 opacity-40">
                <img
                    src="/cyber_logic_matching_bg_1772427624067.png"
                    alt="Cyber Logic"
                    className="w-full h-full object-cover"
                />
            </div>

            {/* Header */}
            <div className="absolute top-8 left-8 right-8 flex justify-between items-start z-10">
                <div className="flex flex-col">
                    <span className="text-xs font-black uppercase text-magenta-400 tracking-[0.4em]">Subsystem Linked</span>
                    <h2 className="text-5xl font-black italic text-white leading-none tracking-tighter">LOGICAL LINK</h2>
                </div>
                <div className="flex flex-col items-end gap-2">
                    <JuicyStreak count={streak} />
                    <div className="bg-white/5 border border-white/10 px-6 py-2 rounded-2xl backdrop-blur-xl">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Data Packets</span>
                        <span className="text-2xl font-black text-white">{score}</span>
                    </div>
                </div>
            </div>

            {/* The Logical Grid */}
            <div className="relative z-10 grid grid-cols-6 gap-2 p-2 bg-white/5 border border-white/10 rounded-[2.5rem] backdrop-blur-3xl shadow-[0_0_100px_rgba(255,0,255,0.1)]">
                {grid.map((row, r) => row.map((gate, c) => (
                    <motion.div
                        key={gate.id}
                        layout
                        initial={{ scale: 0.8, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        exit={{ scale: 0, opacity: 0 }}
                        whileHover={{ scale: 1.1, filter: "brightness(1.2)" }}
                        whileTap={{ scale: 0.9 }}
                        transition={JUICY_SPRINGS.bouncy}
                        className={`w-14 h-14 rounded-xl ${gate.color} flex items-center justify-center cursor-pointer shadow-lg border border-white/20`}
                        onClick={() => handleTileClick(r, c)}
                    >
                        <gate.icon className="text-white w-6 h-6" />
                    </motion.div>
                )))}
            </div>

            {/* Instruction Footer */}
            <div className="mt-12 flex gap-8 z-10">
                <div className="flex items-center gap-3 bg-white/5 border border-white/5 px-4 py-2 rounded-2xl backdrop-blur-md">
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-wider">Goal</span>
                    <span className="text-[10px] font-black text-white uppercase italic">Connect 3+ Matching Gates</span>
                </div>
            </div>

            {/* Pixel's Analytical HUD */}
            <div className="absolute bottom-10 left-10 opacity-30 flex items-center gap-4">
                <div className="flex flex-col gap-1">
                    {[1, 2, 3].map(i => (
                        <motion.div
                            key={i}
                            initial={{ width: 0 }}
                            animate={{ width: "100%" }}
                            transition={{ duration: 1, repeat: Infinity, delay: i * 0.2 }}
                            className="h-[1px] w-12 bg-magenta-500"
                        />
                    ))}
                </div>
                <span className="text-[8px] font-black text-magenta-500 uppercase tracking-widest">Pixel Digital Core: Synchronized</span>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    BookOpen,
    PenTool,
    Sparkles,
    ChevronRight,
    Star,
    Music,
    Palette,
    Lightbulb,
    Mic,
    Heart
} from "lucide-react";
import { hapticSuccess, hapticSelection } from "@/lib/platform/haptics";
import MascotFriend from "../experience/KoydoMascotFriends";

/**
 * LUNA'S LEGEND - Phase 9 (Explorer Batch)
 * A 4K advanced storytelling quest with multi-branching narratives.
 * Theme: Sequential "Explorer" quests (Dora-style) to craft a legendary tale.
 */

interface StoryStep {
    id: string;
    stage: string;
    narrative: string;
    options: {
        text: string;
        impact: string;
        isCorrect: boolean;
    }[];
    x: number;
    y: number;
}

const STORY_STEPS: StoryStep[] = [
    {
        id: "step_1",
        stage: "The Beginning",
        narrative: "Our story starts in the Whispering Woods. Luna finds a glowing feather. What should she do?",
        options: [
            { text: "Follow the light", impact: "Luna follows the trail to a hidden cave.", isCorrect: true },
            { text: "Return to camp", impact: "The story ends too early!", isCorrect: false }
        ],
        x: 20,
        y: 40
    },
    {
        id: "step_2",
        stage: "The Encounter",
        narrative: "Beneath the roots of a giant oak, a silver fox appears. It asks for a rhyme.",
        options: [
            { text: "Sing a song", impact: "The fox dances and reveals a secret path.", isCorrect: true },
            { text: "Climb the tree", impact: "The birds fly away, startled.", isCorrect: false }
        ],
        x: 50,
        y: 60
    },
    {
        id: "step_3",
        stage: "The Legend",
        narrative: "The Great Spirit of the Moon awaits at the summit. Present your gift.",
        options: [
            { text: "Gift of Wisdom", impact: "The moon glows bright with your knowledge.", isCorrect: true },
            { text: "Gift of Gold", impact: "Material things hold no power here.", isCorrect: false }
        ],
        x: 80,
        y: 30
    }
];

export default function LunasLegend() {
    const [stepIndex, setStepIndex] = useState(0);
    const [completedSteps, setCompletedSteps] = useState<string[]>([]);
    const [isComplete, setIsComplete] = useState(false);
    const [impactText, setImpactText] = useState("");
    const [showImpact, setShowImpact] = useState(false);

    const currentStep = STORY_STEPS[stepIndex];

    const handleOptionSelect = (option: typeof currentStep.options[0]) => {
        setImpactText(option.impact);
        setShowImpact(true);

        if (option.isCorrect) {
            hapticSuccess();
            setTimeout(() => {
                setShowImpact(false);
                setCompletedSteps(prev => [...prev, currentStep.id]);
                if (stepIndex < STORY_STEPS.length - 1) {
                    setStepIndex(prev => prev + 1);
                } else {
                    setIsComplete(true);
                }
            }, 2000);
        } else {
            hapticSelection();
            setTimeout(() => {
                setShowImpact(false);
            }, 2000);
        }
    };

    return (
        <div className="relative w-full aspect-video rounded-3xl overflow-hidden bg-slate-900 border border-purple-500/20 shadow-2xl font-sans group">
            {/* 4K Mystical Night Background */}
            <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1518709268805-4e9042af9f23?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center brightness-[0.4] contrast-125" />
            <div className="absolute inset-0 bg-gradient-to-b from-purple-900/20 via-transparent to-slate-900/80" />

            {/* Story Nodes */}
            <div className="absolute inset-0 pointer-events-none">
                {STORY_STEPS.map((step, idx) => (
                    <motion.div
                        key={step.id}
                        initial={{ opacity: 0 }}
                        animate={{
                            opacity: idx <= stepIndex ? 1 : 0.2,
                            scale: idx === stepIndex ? 1.1 : 1
                        }}
                        className="absolute"
                        style={{ left: `${step.x}%`, top: `${step.y}%`, transform: 'translate(-50%, -50%)' }}
                    >
                        <div className={`p-4 rounded-full border-2 backdrop-blur-3xl shadow-2xl ${completedSteps.includes(step.id) ? "bg-purple-500/30 border-purple-400" : "bg-white/5 border-white/20"
                            }`}>
                            <BookOpen className={`w-6 h-6 ${completedSteps.includes(step.id) ? "text-purple-400" : "text-white/40"}`} />
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* HUD: Story Progress (Top) */}
            <div className="absolute top-6 left-1/2 -translate-x-1/2 flex gap-2 p-2 bg-black/30 backdrop-blur-2xl border border-white/10 rounded-2xl">
                {STORY_STEPS.map((_, i) => (
                    <div key={i} className={`w-12 h-1.5 rounded-full ${i <= stepIndex ? "bg-purple-400 shadow-[0_0_10px_rgba(168,85,247,0.5)]" : "bg-white/10"}`} />
                ))}
            </div>

            {/* HUD: Luna Interaction & Narrative (Bottom) */}
            <div className="absolute bottom-6 left-6 right-6">
                <AnimatePresence mode="wait">
                    {!isComplete && (
                        <motion.div
                            key={stepIndex}
                            initial={{ y: 20, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            exit={{ y: -20, opacity: 0 }}
                            className="bg-black/70 backdrop-blur-3xl border border-purple-500/30 rounded-3xl p-8 flex gap-10 items-center overflow-hidden h-64"
                        >
                            <div className="w-24 h-24 relative flex-shrink-0">
                                <MascotFriend id="luna" size="lg" mood={showImpact ? "happy" : "thinking"} />
                            </div>

                            <div className="flex-grow">
                                <AnimatePresence mode="wait">
                                    {showImpact ? (
                                        <motion.div
                                            key="impact"
                                            initial={{ opacity: 0, x: 20 }}
                                            animate={{ opacity: 1, x: 0 }}
                                            exit={{ opacity: 0, x: -20 }}
                                            className="text-purple-300 text-2xl font-light italic leading-relaxed"
                                        >
                                            {impactText}
                                        </motion.div>
                                    ) : (
                                        <motion.div
                                            key="narrative"
                                            initial={{ opacity: 0 }}
                                            animate={{ opacity: 1 }}
                                            className="space-y-4"
                                        >
                                            <h3 className="text-purple-400 font-black text-xs tracking-widest uppercase flex items-center gap-2">
                                                <Music className="w-4 h-4" />
                                                Chapter {stepIndex + 1}: {currentStep.stage}
                                            </h3>
                                            <p className="text-white text-3xl font-medium tracking-tight leading-tight">
                                                {currentStep.narrative}
                                            </p>

                                            <div className="flex gap-4 pt-4">
                                                {currentStep.options.map((option, i) => (
                                                    <button
                                                        key={i}
                                                        onClick={() => handleOptionSelect(option)}
                                                        className="px-6 py-3 bg-white/5 hover:bg-purple-500/20 border border-white/10 hover:border-purple-500/40 rounded-xl text-white font-bold transition-all flex items-center gap-2 group/btn"
                                                    >
                                                        <ChevronRight className="w-4 h-4 text-purple-400 group-hover/btn:translate-x-1 transition-transform" />
                                                        {option.text}
                                                    </button>
                                                ))}
                                            </div>
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Win Screen */}
            <AnimatePresence>
                {isComplete && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
