            </div>
        </div>
    );
}

"use client";

import { motion, AnimatePresence, useDragControls } from "framer-motion";
import { useState, useEffect, useRef, useCallback } from "react";
import { Atom, Zap, Maximize, Target, RefreshCcw, ShieldAlert, Cpu, Layers } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Types --- */
type QuantumParticle = {
    id: string;
    type: "electron" | "photon" | "quark";
    x: number;
    y: number;
    charge: number;
    mass: number;
};

type GravityWell = {
    id: string;
    x: number;
    y: number;
    strength: number;
    targetCharge: number;
};

export default function QuantumQuest() {
    const { setMessage, setMood } = useMascot();
    const [particles, setParticles] = useState<QuantumParticle[]>([]);
    const [wells, setWells] = useState<GravityWell[]>([]);
    const [gameState, setGameState] = useState<"IDLE" | "PLAYING" | "STABILIZED" | "CRITICAL">("IDLE");
    const [energyLevel, setEnergyLevel] = useState(100);
    const [score, setScore] = useState(0);

    const initializeLevel = useCallback(() => {
        const newWells: GravityWell[] = [
            { id: "well-1", x: 30, y: 50, strength: 0.5, targetCharge: 10 },
            { id: "well-2", x: 70, y: 50, strength: 0.5, targetCharge: -10 }
        ];
        setWells(newWells);
        setParticles([]);
        setEnergyLevel(100);
        setGameState("PLAYING");
        setScore(0);
        setMood("thinking");
        setMessage("Quantum stability critical. Deploy particles to balance the gravity wells! ⚛️");
    }, [setMessage, setMood]);

    const deployParticle = (type: QuantumParticle["type"], x: number, y: number) => {
        if (energyLevel <= 0 || gameState !== "PLAYING") return;

        const charges = { electron: -1, photon: 0, quark: 1 };
        const masses = { electron: 1, photon: 0.1, quark: 2 };

        const newParticle: QuantumParticle = {
            id: Math.random().toString(36).substr(2, 9),
            type,
            x: 50, // Origin
            y: 80,
            charge: charges[type],
            mass: masses[type]
        };

        setParticles(prev => [...prev, newParticle]);
        setEnergyLevel(e => Math.max(0, e - 10));
        hapticSelection();
    };

    // Physics Simulation Loop
    useEffect(() => {
        if (gameState !== "PLAYING") return;

        const interval = setInterval(() => {
            setParticles(prev => {
                let updated = prev.map(p => {
                    let nextX = p.x;
                    let nextY = p.y;

                    // Apply forces from wells
                    wells.forEach(well => {
                        const dx = well.x - p.x;
                        const dy = well.y - p.y;
                        const dist = Math.sqrt(dx * dx + dy * dy);
                        const force = (well.strength * p.mass) / (dist * dist + 10);

                        nextX += (dx / dist) * force;
                        nextY += (dy / dist) * force;
                    });

                    // Momentum (simulated)
                    nextY -= 0.5;

                    return { ...p, x: nextX, y: nextY };
                });

                // Check for captures
                updated = updated.filter(p => {
                    const captured = wells.find(w => {
                        const dist = Math.sqrt(Math.pow(w.x - p.x, 2) + Math.pow(w.y - p.y, 2));
                        return dist < 5;
                    });

                    if (captured) {
                        setScore(s => s + 500);
                        hapticSelection();
                        return false;
                    }

                    // Remove if out of bounds
                    return p.x > 0 && p.x < 100 && p.y > 0 && p.y < 100;
                });

                return updated;
            });
        }, 30);

        return () => clearInterval(interval);
    }, [gameState, wells]);

    const startGame = () => {
        initializeLevel();
        hapticSuccess();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[650px] bg-slate-950 rounded-[4rem] border border-white/10 overflow-hidden shadow-2xl flex flex-col font-mono">
            {/* 3D Grid & Space Layers */}
            <div className="absolute inset-0 z-0 overflow-hidden">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(56,189,248,0.15)_0%,transparent_80%)]" />
                <motion.div
                    className="absolute inset-0 opacity-10"
                    style={{
                        backgroundImage: "linear-gradient(#38bdf8 1px, transparent 1px), linear-gradient(90deg, #38bdf8 1px, transparent 1px)",
                        backgroundSize: "50px 50px",
                        perspective: "1000px",
                        rotateX: 60,
                        transformOrigin: "bottom"
                    }}
                    animate={{ backgroundPositionY: ["0px", "100px"] }}
                    transition={{ duration: 5, repeat: Infinity, ease: "linear" }}
                />
            </div>

            {/* UI: HUD Overlay */}
            <div className="relative z-20 p-10 flex justify-between items-start pointer-events-none">
                <div className="space-y-4">
                    <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl">
                        <div className="flex items-center gap-3 mb-2">
                            <Layers className="text-sky-400 w-5 h-5" />
                            <h2 className="text-xl font-black italic tracking-tighter text-white">QUANTUM QUEST</h2>
                        </div>
                        <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.3em]">Singularity Stabilizer v9.1</p>
                    </div>

                    <div className="bg-sky-500/10 border border-sky-500/20 p-5 rounded-[2rem] backdrop-blur-xl">
                        <div className="flex justify-between items-end mb-2">
                            <span className="text-[10px] font-black text-sky-400 uppercase tracking-widest">Quantum Energy</span>
                            <span className="text-xl font-black italic">{energyLevel}%</span>
                        </div>
                        <div className="w-48 h-1.5 bg-white/5 rounded-full overflow-hidden">
                            <motion.div
                                className="h-full bg-sky-500 shadow-[0_0_15px_#0ea5e9]"
                                animate={{ width: `${energyLevel}%` }}
                            />
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl min-w-[140px]">
                        <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Relativity Sync</p>
                        <p className="text-3xl font-black italic tracking-tighter tabular-nums">{score.toLocaleString()}</p>
                    </div>
                </div>
            </div>

            {/* Simulation Space */}
            <div className="relative z-10 flex-1 px-10 pb-10 flex flex-col items-center">
                <div className="relative w-full h-[350px] bg-slate-900/40 rounded-[3rem] border border-white/5 backdrop-blur-sm overflow-hidden border-sky-500/10">
                    {/* Gravity Wells */}
                    {wells.map(well => (
                        <div
                            key={well.id}
                            className="absolute -translate-x-1/2 -translate-y-1/2"
                            style={{ left: `${well.x}%`, top: `${well.y}%` }}
                        >
                            <motion.div
                                className="w-16 h-16 rounded-full border-2 border-dashed border-sky-500/40 flex items-center justify-center"
                                animate={{ rotate: 360 }}
                                transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
                            >
                                <div className="w-8 h-8 rounded-full bg-sky-400/20 flex items-center justify-center">
                                    <Target className="w-4 h-4 text-sky-400 opacity-60" />
                                </div>
                            </motion.div>
                            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 text-center">
                                <span className="text-[8px] font-bold text-sky-500/60 uppercase tracking-widest leading-none">Singularity {well.id.split('-')[1]}</span>
                            </div>
                        </div>
                    ))}

                    {/* Particles */}
                    <AnimatePresence>
                        {particles.map(p => (
                            <motion.div
                                key={p.id}
                                className={`absolute w-3 h-3 rounded-full shadow-lg pointer-events-none
                                    ${p.type === 'electron' ? 'bg-rose-400 shadow-[0_0_10px_#fb7185]' :
                                        p.type === 'photon' ? 'bg-amber-400 shadow-[0_0_10px_#fbbf24]' :
                                            'bg-sky-400 shadow-[0_0_10px_#38bdf8]'}`}
                                style={{
                                    left: `${p.x}%`,
                                    top: `${p.y}%`,
                                    x: "-50%",
                                    y: "-50%"
                                }}
                            />
                        ))}
                    </AnimatePresence>

                    {/* Intro Overlay */}
                    {gameState === "IDLE" && (
                        <motion.div
                            {...JUICY_VARIANTS.slideUp}
                            className="absolute inset-0 z-40 bg-black/80 backdrop-blur-2xl flex flex-col items-center justify-center p-12 text-center"
                        >
                            <div className="bg-sky-500/20 p-6 rounded-[2.5rem] border border-sky-500/30 mb-8">
                                <Atom className="w-16 h-16 text-sky-400 animate-spin-slow" />
                            </div>
                            <h3 className="text-4xl font-black italic tracking-tighter text-white mb-4 uppercase">Quantum Linkage</h3>
                            <p className="text-zinc-400 text-sm max-w-sm mb-12">
                                Launch specialized particles into the gravity wells to stabilize the local quantum field. Don't let the energy core deplete!
                            </p>
                            <PhysicalButton onClick={startGame} className="bg-sky-500 h-20 px-16 rounded-[2.5rem] text-xl">
                                INITIALIZE REACTOR ⚛️
                            </PhysicalButton>
                        </motion.div>
                    )}
                </div>

                {/* Particle Launcher Controls */}
                <div className="mt-8 flex gap-6">
                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('quark', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-sky-500/10 border border-sky-500/30 text-sky-400 hover:bg-sky-500/20"
                        >
                            <Cpu className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">QUARK</span>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('photon', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-amber-500/10 border border-amber-500/30 text-amber-400 hover:bg-amber-500/20"
                        >
                            <Zap className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">PHOTON</span>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('electron', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-rose-500/10 border border-rose-500/30 text-rose-400 hover:bg-rose-500/20"
                        >
                            <Maximize className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">ELECTRON</span>
                    </div>
                </div>
            </div>

            {/* Scanline / CRT Polish */}
            <div className="absolute inset-0 pointer-events-none z-50 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.05)_50%),linear-gradient(90deg,rgba(255,0,0,0.02),rgba(0,255,0,0.01),rgba(0,0,118,0.02))] bg-[length:100%_2px,3px_100%]" />
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Zap, Cpu, Activity, ShieldCheck, Info, ChevronRight, Target, Atom, Sparkles, Binary, Layers, RotateCcw } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Quantum Logic Types --- */
type QubitState = "0" | "1" | "SUPERPOSITION" | "ENTANGLED";
type QuantumGate = "HADAMARD" | "CNOT" | "NOT" | "MEASURE";

interface Qubit {
    id: string;
    state: QubitState;
    entangledWith?: string;
}

export default function QuantumQuirk() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "SOLVING" | "MEASURED" | "SUCCESS">("IDLE");
    const [qubits, setQubits] = useState<Qubit[]>([
        { id: "Q0", state: "0" },
        { id: "Q1", state: "0" }
    ]);
    const [history, setHistory] = useState<string[]>([]);

    const applyGate = (gate: QuantumGate, targetId: string) => {
        if (gameState !== "SOLVING") return;

        hapticSelection();
        setQubits(prev => prev.map(q => {
            if (q.id === targetId) {
                if (gate === "HADAMARD") {
                    return { ...q, state: "SUPERPOSITION" };
                }
                if (gate === "NOT") {
                    return { ...q, state: q.state === "0" ? "1" : "0" };
                }
                if (gate === "MEASURE") {
                    const collapsed = Math.random() > 0.5 ? "1" : "0";
                    return { ...q, state: collapsed as QubitState };
                }
            }
            return q;
        }));

        setHistory(prev => [...prev.slice(-4), gate]);
    };

    const handleCnot = (controlId: string, targetId: string) => {
        if (gameState !== "SOLVING") return;
        hapticSelection();

        const control = qubits.find(q => q.id === controlId);
        if (control?.state === "1") {
            applyGate("NOT", targetId);
        } else if (control?.state === "SUPERPOSITION") {
            setQubits(prev => prev.map(q => {
                if (q.id === targetId || q.id === controlId) {
                    return { ...q, state: "ENTANGLED", entangledWith: q.id === targetId ? controlId : targetId };
                }
                return q;
            }));
            setMessage("Quantum entanglement achieved! Spooky action at a distance detected. ⚛️");
        }
    };

    const checkSolution = () => {
        const measured = qubits.every(q => q.state === "0" || q.state === "1");
        if (measured) {
            setGameState("SUCCESS");
            hapticSuccess();
            setMessage("Algorithm stabilized. Quantum decoherence avoided! 🏆");
            setMood("happy");
        } else {
            hapticError();
            setMessage("State is still in flux. Collapse the wave function to confirm. 🌊");
        }
    };

    const startQuantumLab = () => {
        setGameState("SOLVING");
        setMood("thinking");
        setMessage("Welcome to the Subatomic Lab. Initialize the qubits and prepare for entanglement. ⚛️");
        hapticSelection();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-slate-950/20 rounded-[4rem] border border-cyan-500/20 overflow-hidden shadow-2xl flex flex-col font-sans text-white">
            {/* Cyberpunk Grid Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[linear-gradient(to_right,#0891b210_1px,transparent_1px),linear-gradient(to_bottom,#0891b210_1px,transparent_1px)] bg-[size:40px_40px]" />
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(6,182,212,0.1)_0%,transparent_70%)]" />
            </div>

            {/* HUD Header */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-black/40 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-cyan-500/10 border border-cyan-500/30 flex items-center justify-center">
                        <Atom className="text-cyan-400 w-8 h-8 animate-spin-slow" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Quantum Quirk</h2>
                        <span className="text-[10px] font-bold text-cyan-600 uppercase tracking-widest">State Processor v2.0</span>
                    </div>
                </div>

                <div className="flex gap-6">
                    <StatusIndicator label="COHERENCE" value="98.2%" color="text-cyan-400" />
                    <StatusIndicator label="ENTROPY" value="Low" color="text-emerald-400" />
                    <div className="bg-white/5 border border-white/5 px-6 py-2 rounded-2xl">
                        <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest block mb-1">STABILITY</span>
                        <div className="flex gap-1">
                            {[1, 2, 3, 4, 5].map(i => (
                                <div key={i} className={`w-3 h-3 rounded-sm ${i < 4 ? 'bg-cyan-500' : 'bg-white/10'}`} />
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Lab Area */}
            <div className="relative z-10 flex-1 flex overflow-hidden">
                {/* Gate Library */}
                <div className="w-72 border-r border-white/5 p-8 flex flex-col gap-6 bg-black/20">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2">Gate Library</h3>

                    <GateButton
                        label="Hadamard"
                        icon={Sparkles}
                        color="from-purple-500 to-indigo-600"
                        desc="Create Superposition"
                        onClick={() => applyGate("HADAMARD", "Q0")}
                    />
                    <GateButton
                        label="Pauli-X"
                        icon={Binary}
                        color="from-rose-500 to-orange-600"
                        desc="Flip Qubit State"
                        onClick={() => applyGate("NOT", "Q0")}
                    />
                    <GateButton
                        label="CNOT"
                        icon={Layers}
                        color="from-cyan-500 to-blue-600"
                        desc="Entangle Qubits"
                        onClick={() => handleCnot("Q0", "Q1")}
                    />
                    <GateButton
                        label="Measure"
                        icon={Activity}
                        color="from-emerald-500 to-teal-600"
                        desc="Collapse State"
                        onClick={() => applyGate("MEASURE", "Q0")}
                    />

                    <div className="mt-auto pt-6 border-t border-white/5 text-center">
                        <button
                            onClick={() => {
                                setQubits([{ id: "Q0", state: "0" }, { id: "Q1", state: "0" }]);
                                setHistory([]);
                                hapticSelection();
                            }}
                            className="text-[9px] font-black text-zinc-500 hover:text-white uppercase tracking-widest flex items-center justify-center gap-2 transition-colors mx-auto"
                        >
                            <RotateCcw className="w-3 h-3" /> Reset Circuit
                        </button>
                    </div>
                </div>

                {/* Quantum Circuit Visualizer */}
                <div className="flex-1 relative p-12 flex flex-col justify-center gap-16 overflow-hidden">
                    {/* Circuit Lines */}
                    <div className="absolute inset-0 flex flex-col justify-center gap-16 px-12 opacity-10 pointer-events-none">
                        <div className="h-0.5 w-full bg-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.5)]" />
                        <div className="h-0.5 w-full bg-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.5)]" />
                    </div>

                    {qubits.map((q, idx) => (
                        <div key={q.id} className="relative flex items-center gap-12 group">
                            <span className="text-sm font-black text-cyan-500/40 w-8">{q.id}</span>

                            <motion.div
                                layout
                                className={`relative w-40 h-40 rounded-[2.5rem] border-2 bg-black/60 backdrop-blur-3xl flex items-center justify-center overflow-hidden transition-all duration-500
                                ${q.state === "SUPERPOSITION" ? 'border-purple-500/50 shadow-[0_0_40px_rgba(168,85,247,0.2)]' :
                                        q.state === "ENTANGLED" ? 'border-cyan-500/50 shadow-[0_0_40px_rgba(6,182,212,0.2)]' :
                                            'border-white/5'}`}
                            >
                                <AnimatePresence mode="wait">
                                    <QubitVisual state={q.state} key={q.state} />
                                </AnimatePresence>

                                {/* Interference Patterns */}
                                {q.state === "SUPERPOSITION" && (
                                    <motion.div
                                        animate={{ opacity: [0.1, 0.3, 0.1], scale: [1, 1.2, 1] }}
                                        transition={{ duration: 2, repeat: Infinity }}
                                        className="absolute inset-0 bg-purple-500/10 blur-xl pointer-events-none"
                                    />
                                )}
                            </motion.div>

                            <div className="flex flex-col gap-1">
                                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">STATE</span>
                                <span className={`text-xl font-black italic italic uppercase ${q.state === "SUPERPOSITION" ? "text-purple-400" : q.state === "ENTANGLED" ? "text-cyan-400" : "text-white"}`}>
                                    {q.state}
                                </span>
