                <div className="flex-1 relative aspect-square bg-slate-900/50 rounded-[2.5rem] border border-white/10 backdrop-blur-sm overflow-hidden border-sky-500/20 shadow-[inset_0_0_50px_rgba(14,165,233,0.1)]">
